import { useState, useEffect } from "react";
import "./Recruitment.css";

function InternalPortal() {

  const [jobs, setJobs] = useState([]);
  const [title, setTitle] = useState("");
  const [department, setDepartment] = useState("");
  const [desc, setDesc] = useState("");

  const [editId, setEditId] = useState(null);

  // Load Jobs From LocalStorage
  useEffect(() => {
    const saved = JSON.parse(localStorage.getItem("internalJobs")) || [];
    setJobs(saved);
  }, []);

  // Save to LocalStorage Helper
  const saveJobs = (updated) => {
    setJobs(updated);
    localStorage.setItem("internalJobs", JSON.stringify(updated));
  };

  // Create or Update Job
  const handlePost = () => {
    if (!title.trim() || !department.trim() || !desc.trim())
      return alert("Please fill all fields");

    // If Editing Existing Job
    if (editId !== null) {
      const updated = jobs.map(job =>
        job.id === editId
          ? { ...job, title, department, desc }
          : job
      );

      saveJobs(updated);
      alert("Job Updated Successfully");
      setEditId(null);
    } 
    else {
      // New Job
      const newJob = {
        id: Date.now(),
        title,
        department,
        desc
      };

      const updated = [...jobs, newJob];
      saveJobs(updated);
      alert("Job Posted Successfully");
    }

    setTitle("");
    setDepartment("");
    setDesc("");
  };

  // Delete Job
  const handleDelete = (id) => {
    if (!window.confirm("Are you sure you want to delete this job?")) return;

    const updated = jobs.filter(job => job.id !== id);
    saveJobs(updated);
  };

  // Edit Job
  const handleEdit = (job) => {
    setEditId(job.id);
    setTitle(job.title);
    setDepartment(job.department);
    setDesc(job.desc);
  };

  return (
    <div className="designation-container">
      <h2>Internal Job Portal</h2>

      {/* Input Row */}
      <div className="designation-form">
        <input
          type="text"
          placeholder="Job Title e.g Senior Developer"
          value={title}
          onChange={(e) => setTitle(e.target.value)}
        />

        <input
          type="text"
          placeholder="Department"
          value={department}
          onChange={(e) => setDepartment(e.target.value)}
        />

        <input
          type="text"
          placeholder="Short Job Description"
          value={desc}
          onChange={(e) => setDesc(e.target.value)}
        />

        <button onClick={handlePost}>
          {editId ? "Update Job" : "Post Job"}
        </button>
      </div>

      {/* Jobs Table */}
      <table className="designation-table">
        <thead>
          <tr>
            <th>S.No</th>
            <th>Job Title</th>
            <th>Department</th>
            <th>Description</th>
            <th>Action</th>
          </tr>
        </thead>

        <tbody>
          {jobs.length === 0 ? (
            <tr>
              <td colSpan="5">No Internal Jobs Posted Yet</td>
            </tr>
          ) : (
            jobs.map((job, index) => (
              <tr key={job.id}>
                <td>{index + 1}</td>
                <td>{job.title}</td>
                <td>{job.department}</td>
                <td>{job.desc}</td>

                <td>
                  <div className="action-buttons">
                    <button
                      className="job-edit-btn"
                      onClick={() => handleEdit(job)}
                    >
                      Edit
                    </button>

                    <button
                      className="job-delete-btn"
                      onClick={() => handleDelete(job.id)}
                    >
                      Delete
                    </button>
                  </div>
                </td>
              </tr>
            ))
          )}
        </tbody>
      </table>

    </div>
  );
}

export default InternalPortal;
